2	 * Revise engine — quick (Animator-backed).
3	 *
4	 * Summons an anima to address review findings. If the review passed, the
5	 * prompt instructs the anima to confirm and exit without unnecessary changes.
6	 * If the review failed, the prompt directs the anima to address each item
7	 * in the findings and commit the result.
8	 *
9	 * Returns `{ status: 'launched', sessionId }` so the Spider's collect step
10	 * can store ReviseYields on completion.
11	 */
12	
13	import { execFile } from 'node:child_process';
14	import { promisify } from 'node:util';
15	import { guild } from '@shardworks/nexus-core';
16	import type { EngineDesign } from '@shardworks/fabricator-apparatus';
17	import type { AnimatorApi } from '@shardworks/animator-apparatus';
18	import type { WritDoc } from '@shardworks/clerk-apparatus';
19	import type { DraftYields, ReviewYields } from '../types.ts';
20	
21	const execFileAsync = promisify(execFile);
22	
23	async function gitStatus(cwd: string): Promise<string> {
24	  try {
25	    const { stdout } = await execFileAsync('git', ['status', '--porcelain'], { cwd });
26	    return stdout;
27	  } catch {
28	    return '';
29	  }
30	}
31	
32	async function gitDiffUncommitted(cwd: string): Promise<string> {
33	  try {
34	    const { stdout } = await execFileAsync('git', ['diff', 'HEAD'], { cwd });
35	    return stdout;
36	  } catch {
37	    return '';
38	  }
39	}
40	
41	function assembleRevisionPrompt(writ: WritDoc, review: ReviewYields, status: string, diff: string): string {
42	  const reviewResult = review.passed ? 'PASS' : 'FAIL';
43	  const instructions = review.passed
44	    ? `The review passed. No changes are required. Confirm the work looks correct\nand exit. Do not make unnecessary changes or spend unnecessary time reassessing.`
45	    : `The review identified issues that need to be addressed. See "Required Changes"\nin the findings above. Address each item, then commit your changes.`;
46	
47	  const diffSection = diff.trim()
48	    ? `\`\`\`diff\n${diff}\n\`\`\``
49	    : '(No uncommitted changes.)';
50	
51	  return `# Revision Pass
52	
53	You are revising prior work on a commission based on review findings.
54	
55	## The Commission (Spec)
56	
57	${writ.body}
58	
59	## Review Findings
60	
61	${review.findings}
62	
63	## Review Result: ${reviewResult}
64	
