406	      const provider = resolveProvider(config);
407	      const model = resolveModel();
408	      const providerConfig = buildProviderConfig(request, model);
409	
410	      // Step 1: use pre-generated session id if provided (from summon()),
411	      // otherwise generate one. Capture startedAt.
412	      const id = request.sessionId ?? generateId('ses', 4);
413	      const startedAt = new Date().toISOString();
414	
